using System.Collections.Generic;namespace BgCommon.UI.Designer.DataBinding{    /// <summary>    /// 数据源接口    /// </summary>    public interface IDataSource    {        /// <summary>        /// 数据源名称        /// </summary>        string Name { get; }                /// <summary>        /// 数据源类型        /// </summary>        string Type { get; }                /// <summary>        /// 数据源描述        /// </summary>        string Description { get; }                /// <summary>        /// 连接字符串        /// </summary>        string ConnectionString { get; set; }                /// <summary>        /// 数据源是否已连接        /// </summary>        bool IsConnected { get; }                /// <summary>        /// 连接数据源        /// </summary>        /// <returns>是否连接成功</returns>        bool Connect();                /// <summary>        /// 断开数据源连接        /// </summary>        void Disconnect();                /// <summary>        /// 获取数据源结构        /// </summary>        /// <returns>数据源结构</returns>        DataSourceStructure GetStructure();                /// <summary>        /// 获取数据        /// </summary>        /// <param name="query">查询语句</param>        /// <returns>数据结果</returns>        object GetData(string query);    }        /// <summary>    /// 数据源结构    /// </summary>    public class DataSourceStructure    {        /// <summary>        /// 表集合        /// </summary>        public List<DataTable> Tables { get; set; } = new List<DataTable>();                /// <summary>        /// 视图集合        /// </summary>        public List<DataView> Views { get; set; } = new List<DataView>();                /// <summary>        /// 存储过程集合        /// </summary>        public List<StoredProcedure> StoredProcedures { get; set; } = new List<StoredProcedure>();    }        /// <summary>    /// 数据表    /// </summary>    public class DataTable    {        /// <summary>        /// 表名        /// </summary>        public string Name { get; set; }                /// <summary>        /// 列集合        /// </summary>        public List<DataColumn> Columns { get; set; } = new List<DataColumn>();    }        /// <summary>    /// 数据列    /// </summary>    public class DataColumn    {        /// <summary>        /// 列名        /// </summary>        public string Name { get; set; }                /// <summary>        /// 数据类型        /// </summary>        public string Type { get; set; }                /// <summary>        /// 是否为主键        /// </summary>        public bool IsPrimaryKey { get; set; }    }        /// <summary>    /// 数据视图    /// </summary>    public class DataView    {        /// <summary>        /// 视图名        /// </summary>        public string Name { get; set; }                /// <summary>        /// 列集合        /// </summary>        public List<DataColumn> Columns { get; set; } = new List<DataColumn>();    }        /// <summary>    /// 存储过程    /// </summary>    public class StoredProcedure    {        /// <summary>        /// 存储过程名        /// </summary>        public string Name { get; set; }                /// <summary>        /// 参数集合        /// </summary>        public List<ProcedureParameter> Parameters { get; set; } = new List<ProcedureParameter>();    }        /// <summary>    /// 存储过程参数    /// </summary>    public class ProcedureParameter    {        /// <summary>        /// 参数名        /// </summary>        public string Name { get; set; }                /// <summary>        /// 数据类型        /// </summary>        public string Type { get; set; }                /// <summary>        /// 是否为输入参数        /// </summary>        public bool IsInput { get; set; }                /// <summary>        /// 是否为输出参数        /// </summary>        public bool IsOutput { get; set; }    }}